/**
 * Repertoire transcoded from public-domain Mutopia Project MIDI via scripts/midiToCatalog.ts
 * (grades/sections/tempi editorial), same pipeline and convention as catalogImported.ts.
 * This batch covers grades 2-3 of the newly added repertoire. Sources:
 * https://www.mutopiaproject.org -- see each song's sourceNote for the specific piece
 * and bars kept.
 */
type N = [number, number, number]

const notes = (hand: Hand, ns: N[]): SongNote[] =>
  ns.map(([midi, startBeat, durationBeats]) => ({ midi, startBeat, durationBeats, hand }))

const bar = (rh: N[], lh: N[]): SongMeasure => ({ notes: [...notes('R', rh), ...notes('L', lh)] })

